// review.entity.ts
import { Entity, PrimaryGeneratedColumn, Column, ManyToOne, OneToOne, JoinColumn, CreateDateColumn, UpdateDateColumn, Index } from 'typeorm';
import { User } from '../../users/entities/user.entity';
import { Product } from '../../products/entities/product.entity';

export enum Rating {
  ONE_STAR = 1,
  TWO_STARS = 2,
  THREE_STARS = 3,
  FOUR_STARS = 4,
  FIVE_STARS = 5,
}

@Entity('reviews')
@Index(['user', 'product'], { unique: true }) // Un seul avis par (user, product)
export class Review {
  @PrimaryGeneratedColumn()
  id: number;

  @ManyToOne(() => User, (user) => user.reviews)
  user: User;

  @ManyToOne(() => Product, (product) => product.reviews)
  product: Product;

  @Column({ type: 'enum', enum: Rating })
  rating: Rating;

  @Column({ type: 'text', nullable: true, length: 1000 })
  comment: string;

  @Column({ type: 'simple-array', nullable: true })
  images: string[]; // URLs des images uploadées

  @Column({ default: false })
  verifiedPurchase: boolean; // Indique si l'achat est vérifié

  @CreateDateColumn()
  createdAt: Date;

  @UpdateDateColumn()
  updatedAt: Date;

  @OneToOne(() => ReviewResponse, (response) => response.review, { nullable: true })
  response: ReviewResponse;
}

