// reviews.service.ts
import { Injectable } from '@nestjs/common';
import { InjectRepository } from '@nestjs/typeorm';
import { Repository, MoreThanOrEqual } from 'typeorm';
import { Order } from '../orders/entities/order.entity';
import { OrderStatus } from '../orders/enums/order-status.enum';

@Injectable()
export class ReviewsService {
  constructor(
    @InjectRepository(Order)
    private orderRepository: Repository<Order>,
  ) {}

  async canUserReviewProduct(userId: number, productId: number): Promise<boolean> {
    const thirtyDaysAgo = new Date();
    thirtyDaysAgo.setDate(thirtyDaysAgo.getDate() - 30);

    const result = await this.orderRepository
      .createQueryBuilder('order')
      .innerJoin('order.items', 'item')
      .where('order.userId = :userId', { userId })
      .andWhere('item.productId = :productId', { productId })
      .andWhere('order.status = :status', { status: OrderStatus.DELIVERED })
      .andWhere('order.deliveredAt >= :thirtyDaysAgo', { thirtyDaysAgo })
      .getCount();

    return result > 0;
  }
}
```
Explication : Une requête SQL unique est plus efficace que de charger toutes les commandes de l'utilisateur en mémoire (qui pourrait être volumineux) puis de les parcourir. La base de données indexée (sur userId, status, deliveredAt) exécute cette requête en O(log n) au lieu de O(n) côté application, et évite le transfert de données inutiles.

