// reviews.service.ts
async updateProductRating(productId: number, transactionManager?: EntityManager): Promise<void> {
  const manager = transactionManager || this.dataSource.manager;

  const result = await manager
    .createQueryBuilder(Review, 'review')
    .select('AVG(review.rating)', 'average')
    .addSelect('COUNT(review.id)', 'count')
    .where('review.productId = :productId', { productId })
    .getRawOne();

  const averageRating = result.average ? parseFloat(result.average).toFixed(2) : 0;
  const reviewsCount = parseInt(result.count);

  await manager.update(Product, productId, {
    averageRating,
    reviewsCount,
  });
}

// Dans la méthode create()
async create(userId: number, createReviewDto: CreateReviewDto): Promise<Review> {
  const queryRunner = this.dataSource.createQueryRunner();
  await queryRunner.connect();
  await queryRunner.startTransaction();

  try {
    const review = queryRunner.manager.create(Review, {
      ...createReviewDto,
      userId,
      verifiedPurchase: await this.canUserReviewProduct(userId, createReviewDto.productId),
    });
    const savedReview = await queryRunner.manager.save(review);

    // Mise à jour du produit dans la même transaction
    await this.updateProductRating(createReviewDto.productId, queryRunner.manager);

    await queryRunner.commitTransaction();
    return savedReview;
  } catch (error) {
    await queryRunner.rollbackTransaction();
    throw error;
  } finally {
    await queryRunner.release();
  }
}
