// reviews.service.ts
async flagReview(userId: number, reviewId: number, flagDto: CreateFlagDto): Promise<ReviewFlag> {
  const queryRunner = this.dataSource.createQueryRunner();
  await queryRunner.connect();
  await queryRunner.startTransaction();

  try {
    // Vérifier que l'utilisateur n'a pas déjà signalé cet avis
    const existingFlag = await queryRunner.manager.findOne(ReviewFlag, {
      where: { user: { id: userId }, review: { id: reviewId } },
    });
    if (existingFlag) {
      throw new BadRequestException('Vous avez déjà signalé cet avis');
    }

    // Créer le flag
    const flag = queryRunner.manager.create(ReviewFlag, {
      user: { id: userId },
      review: { id: reviewId },
      ...flagDto,
    });
    const savedFlag = await queryRunner.manager.save(flag);

    // Compter les signalements de cet avis
    const flagsCount = await queryRunner.manager.count(ReviewFlag, {
      where: { review: { id: reviewId } },
    });

    // Si seuil atteint, masquer l'avis
    if (flagsCount >= 5) {
      await queryRunner.manager.update(Review, reviewId, {
        status: 'hidden',
      });
    }

    await queryRunner.commitTransaction();
    return savedFlag;
  } catch (error) {
    await queryRunner.rollbackTransaction();
    throw error;
  } finally {
    await queryRunner.release();
  }
}
