// products.service.ts
async findTopRatedProducts(page: number = 1, limit: number = 20): Promise<[Product[], number]> {
  const skip = (page - 1) * limit;

  return this.productRepository.findAndCount({
    where: {
      averageRating: MoreThanOrEqual(4),
      reviewsCount: MoreThan(0), // Exclure les produits sans avis
    },
    order: {
      averageRating: 'DESC',
      reviewsCount: 'DESC', // En cas d'égalité, le plus d'avis d'abord
    },
    skip,
    take: limit,
  });
}
