// reviews.service.ts
async getRatingDistribution(productId: number): Promise<{ rating: number; count: number }[]> {
  const distribution = await this.reviewRepository
    .createQueryBuilder('review')
    .select('review.rating', 'rating')
    .addSelect('COUNT(review.id)', 'count')
    .where('review.productId = :productId', { productId })
    .andWhere('review.status = :status', { status: 'visible' })
    .groupBy('review.rating')
    .orderBy('review.rating', 'ASC')
    .getRawMany();

  // Compléter les notes manquantes (ex: 0 avis pour 2 étoiles)
  const fullDistribution = [];
  for (let rating = 1; rating <= 5; rating++) {
    const found = distribution.find(d => parseInt(d.rating) === rating);
    fullDistribution.push({
      rating,
      count: found ? parseInt(found.count) : 0,
    });
  }
  return fullDistribution;
}
```
Retour : un tableau d'objets `{ rating: 1, count: 3 }`, `{ rating: 2, count: 0 }`, etc. Cela permet d'afficher facilement la répartition des étoiles dans l'interface utilisateur.
